import{_ as i,o as a,c as t,ao as s}from"./chunks/framework.BwTKejc4.js";const k=JSON.parse('{"title":"Improving convergence","description":"","frontmatter":{},"headers":[],"relativePath":"model-guides/convergence.md","filePath":"model-guides/convergence.md","lastUpdated":null}'),n={name:"model-guides/convergence.md"};function r(o,e,d,l,h,c){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="Improving-convergence" tabindex="-1">Improving convergence <a class="header-anchor" href="#Improving-convergence" aria-label="Permalink to &quot;Improving convergence {#Improving-convergence}&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Status — Stable</p><p>Mirrors drmTMB&#39;s <a href="https://itchyshin.github.io/drmTMB/articles/convergence.html" target="_blank" rel="noreferrer">Improving convergence</a>. A practical guide to checking and improving a fit in <strong>DRM.jl</strong>, built around the <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.check_drm"><code>check_drm</code></a> diagnostic.</p></div><p>A distributional regression fits by maximum likelihood: <code>drm</code> runs an LBFGS optimiser (with a robust mode-finder for the phylogenetic engine) and stores whether it converged. Most models converge without intervention. This page is for the ones that don&#39;t — and how to tell the difference between a real problem and a model that is simply sitting at the edge of its parameter space.</p><h2 id="Step-1-—-check-the-fit" tabindex="-1">Step 1 — check the fit <a class="header-anchor" href="#Step-1-—-check-the-fit" aria-label="Permalink to &quot;Step 1 — check the fit {#Step-1-—-check-the-fit}&quot;">​</a></h2><p>Every fit carries a convergence flag and an observed-information covariance. <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#DRM.check_drm"><code>check_drm</code></a> bundles the useful diagnostics into one report:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> DRM</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> drm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x)), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gaussian</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(); data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dat)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">check_drm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fit)</span></span></code></pre></div><p>The report is a <code>NamedTuple</code>:</p><ul><li><p><code>converged</code> — did the optimiser report success?</p></li><li><p><code>max_abs_grad</code> — <code>max|∇nll|</code> at the solution. Near a clean interior optimum this is ≈ 0; a large value means the optimiser stopped early.</p></li><li><p><code>vcov_posdef</code> — is the covariance positive-definite? When this is <code>false</code>, some parameters have no finite standard error (drmTMB&#39;s <code>sdreport</code> returns all <code>NaN</code> in exactly this situation).</p></li><li><p><code>min_eigval</code> / <code>cond</code> — the smallest eigenvalue and the condition number of the covariance. A near-zero <code>min_eigval</code> flags a direction the data barely constrain (a variance pinned near zero, two confounded coefficients).</p></li><li><p><code>ok</code> — <code>true</code> when converged, the gradient is small, and the covariance is PD.</p></li></ul><h2 id="Step-2-—-read-the-failure-mode" tabindex="-1">Step 2 — read the failure mode <a class="header-anchor" href="#Step-2-—-read-the-failure-mode" aria-label="Permalink to &quot;Step 2 — read the failure mode {#Step-2-—-read-the-failure-mode}&quot;">​</a></h2><p>A non-<code>ok</code> report is information, not necessarily an error.</p><h3 id="A-variance-at-the-boundary" tabindex="-1">A variance at the boundary <a class="header-anchor" href="#A-variance-at-the-boundary" aria-label="Permalink to &quot;A variance at the boundary {#A-variance-at-the-boundary}&quot;">​</a></h3><p>If a random-effect SD or a scale parameter is estimated near zero, the likelihood flattens in that direction: <code>min_eigval</code> is tiny and the gradient may not reach zero. This is often the <em>correct</em> MLE — the data carry little of that variance component. The other parameters still have valid Wald standard errors; only the boundary direction is undefined. Prefer <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.confint"><code>confint</code></a><code>(fit; method = :profile)</code> there: the profile interval is exact under the likelihood-ratio statistic where the quadratic Wald approximation breaks down at a boundary.</p><h3 id="Confounded-predictors" tabindex="-1">Confounded predictors <a class="header-anchor" href="#Confounded-predictors" aria-label="Permalink to &quot;Confounded predictors {#Confounded-predictors}&quot;">​</a></h3><p>A near-singular covariance with a large <code>cond</code> usually means two columns of a design matrix are nearly collinear (e.g. an intercept and a centred covariate that is almost constant). Re-centre or drop one; refit.</p><h3 id="Stopped-early" tabindex="-1">Stopped early <a class="header-anchor" href="#Stopped-early" aria-label="Permalink to &quot;Stopped early {#Stopped-early}&quot;">​</a></h3><p>If <code>converged</code> is <code>false</code> but <code>max_abs_grad</code> is still sizable, the optimiser ran out of iterations rather than hitting a boundary. Tighten the gradient tolerance and refit:</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fit </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> drm</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">bf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(y </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">@formula</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sigma </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x)), </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Gaussian</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">          data </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dat, g_tol </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1e-10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="Step-3-—-scale-and-standardise" tabindex="-1">Step 3 — scale and standardise <a class="header-anchor" href="#Step-3-—-scale-and-standardise" aria-label="Permalink to &quot;Step 3 — scale and standardise {#Step-3-—-scale-and-standardise}&quot;">​</a></h2><p>Most convergence trouble is conditioning. Two cheap fixes:</p><ul><li><p><strong>Standardise covariates.</strong> Predictors on wildly different scales make the Hessian ill-conditioned. Centre and scale continuous covariates before fitting.</p></li><li><p><strong>Use ML for model comparison.</strong> ML is the default and is comparable across fixed-effect structures; REML likelihoods are not. Keep ML when selecting models with <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.aic"><code>aic</code></a> / <a href="/DRM.jl/dev/reference/model-fitting-and-postfit#StatsAPI.bic"><code>bic</code></a>.</p></li></ul><h2 id="The-phylogenetic-engine" tabindex="-1">The phylogenetic engine <a class="header-anchor" href="#The-phylogenetic-engine" aria-label="Permalink to &quot;The phylogenetic engine {#The-phylogenetic-engine}&quot;">​</a></h2><p>The verified q=4 phylogenetic location–scale engine has its own mode-finder (sparse augmented-state Laplace with an exact O(p) gradient). Two notes specific to it:</p><ul><li><p><strong>Off-diagonal initialisation.</strong> Starting the cross-covariance Cholesky away from zero (the <code>lc3</code>/<code>lc7</code> entries) avoids a saddle near the diagonal start.</p></li><li><p><strong>The Watanabe-singular boundary.</strong> When a per-axis phylogenetic variance is near zero the model sits at a singular point; the optimiser flags the plateau rather than chasing a flat ridge. This matches drmTMB&#39;s behaviour (it reports &quot;false convergence&quot;) — both engines are correct; the geometry, not the optimiser, is the limiting factor.</p></li></ul>`,23)])])}const g=i(n,[["render",r]]);export{k as __pageData,g as default};
